#include <iostream> #include <string> using namespace std; class Carro { public: string modelo; private: double velocidadeInstantanea; public: Carro() { velocidadeInstantanea = 0; } void acelerar(double taxa) { velocidadeInstantanea += taxa; } double getVelocidade() { return velocidadeInstantanea; } }; int main() { Carro meuCarro; meuCarro.modelo = "Ferrari"; cout << "Modelo: " << meuCarro.modelo << endl; meuCarro.acelerar(10); meuCarro.acelerar(20); meuCarro.acelerar(5); cout << "Velocidade final: " << meuCarro.getVelocidade() << " km/h" << endl; return 0; }